import React from 'react';
import ReactDOM from 'react-dom';
import * as $ from 'jquery'
import './index.css';
import App from './App';
import profileContext from './components/context/profilecontext'
import CartContext from './components/context/CartContext'
import SweetAlertContext from './components/context/SweetAlertContext'

ReactDOM.render(
  <React.StrictMode>
    <SweetAlertContext>
    <CartContext>
    <profileContext>
      <App />
    </profileContext>
    </CartContext>
    </SweetAlertContext>
  </React.StrictMode>,
  document.getElementById('root')
);
